#include <bits/stdc++.h>
using namespace std;

int n, a[100005];

void quick_sort(int a[], int l, int r) {
    int i = l, j = r, mid = a[(l + r) >> 1];
    while (i <= j) {
        while (a[i] < mid) i++;
        while (a[j] > mid) j--;
        if (i <= j) swap(a[i++], a[j--]);
    }
    if (l < j) quick_sort(a, l, j);
    if (i < r) quick_sort(a, i, r);
}

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    quick_sort(a, 0, n - 1);
    for (int i = 0; i < n; i++) {
        cout << a[i] << ' ';
    }
    return 0;
}
